import React, { useEffect, useState } from 'react';
import { getProject, createTask, updateTask } from '../services/api';
import TaskCard from './TaskCard';

export default function KanbanBoard({ project }){
  const [projectData,setProjectData]=useState(project);
  const [title,setTitle]=useState('');

  useEffect(()=>{ load(); },[project]);
  async function load(){
    const p = await getProject(project.id);
    setProjectData(p);
  }

  async function addTask(e){
    e.preventDefault();
    const t = await createTask({title,project:project.id});
    setProjectData({...projectData, tasks:[t,...projectData.tasks]});
    setTitle('');
  }

  async function moveTask(taskId, status){
    const t = await updateTask(taskId, {status});
    // optimistic update
    setProjectData(prev=>{
      const tasks = prev.tasks.map(x=> x.id===t.id? t: x);
      return {...prev, tasks}
    });
  }

  const columns = [
    {key:'todo', title:'Todo'},
    {key:'inprogress', title:'In Progress'},
    {key:'review', title:'Review'},
    {key:'done', title:'Completed'},
  ];

  return (
    <div>
      <h3>{projectData.name}</h3>
      <form onSubmit={addTask} className="card">
        <input placeholder="New task title" value={title} onChange={e=>setTitle(e.target.value)} />
        <button>Create Task</button>
      </form>
      <div className="kanban">
        {columns.map(col=> (
          <div key={col.key} className="column">
            <h4>{col.title}</h4>
            <div className="column-body">
              {projectData.tasks && projectData.tasks.filter(t=>t.status===col.key).map(t=> (
                <TaskCard key={t.id} task={t} onMove={(status)=>moveTask(t.id,status)} />
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}
